#include <bits/stdc++.h>
#include <iostream>
#include <cstring>
#include <algorithm>
using namespace std;
int main()
{
    long long n;
    int days = 0;
    int nday = 0;
    cin >> n;
    int sheng = n;
    while (sheng > 0)
    {
        int b = sheng % 3;
        int qu = (sheng + 2) / 3;
        sheng = sheng - qu;
        if (b == 1 && nday == 0) {
            nday = days + 1;
        }
        //cout << sheng << endl;
        days++;
    }
    cout << days << " "<< nday << endl;



    return 0;
}
